import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as l}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"افزودن Yandex Channel","description":"","frontmatter":{},"headers":[],"relativePath":"fa/upload/yandex.md","filePath":"fa/upload/yandex.md","lastUpdated":1781962217000}'),r={name:"fa/upload/yandex.md"};function p(c,e,h,u,m,x){return s(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="افزودن-yandex-channel" tabindex="-1">افزودن Yandex Channel <a class="header-anchor" href="#افزودن-yandex-channel" aria-label="Permalink to &quot;افزودن Yandex Channel&quot;">​</a></h1><h2 id="ابتدا-چه-چیزهایی-لازم-است" tabindex="-1">ابتدا چه چیزهایی لازم است <a class="header-anchor" href="#ابتدا-چه-چیزهایی-لازم-است" aria-label="Permalink to &quot;ابتدا چه چیزهایی لازم است&quot;">​</a></h2><table tabindex="0"><thead><tr><th>مورد</th><th>چرا لازم است</th></tr></thead><tbody><tr><td>Yandex account</td><td>برای sign in و authorize کردن Yandex Disk</td></tr><tr><td>Yandex OAuth app</td><td>برای ساخت <code>Client ID</code> و <code>Client Secret</code></td></tr><tr><td>دامنه ImgBed شما</td><td>برای OAuth redirect URI</td></tr><tr><td>فضای Yandex Disk در دسترس</td><td>به‌عنوان محل واقعی ذخیره files</td></tr></tbody></table><h2 id="مراحل-setup" tabindex="-1">مراحل setup <a class="header-anchor" href="#مراحل-setup" aria-label="Permalink to &quot;مراحل setup&quot;">​</a></h2><h3 id="step-1-ساخت-yandex-oauth-app" tabindex="-1">Step 1: ساخت Yandex OAuth App <a class="header-anchor" href="#step-1-ساخت-yandex-oauth-app" aria-label="Permalink to &quot;Step 1: ساخت Yandex OAuth App&quot;">​</a></h3><ol><li>صفحه ساخت Yandex OAuth app را باز کنید:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>اگر به sign in هدایت شدید، ابتدا با Yandex account وارد شوید.</li><li>app جدید بسازید.</li><li>یک نام قابل‌تشخیص بگذارید، مثل <code>imgbed-yandex</code>.</li><li>تنظیمات callback یا redirect URL را پیدا کنید.</li><li>وارد کنید:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-confirm-کردن-permissions" tabindex="-1">Step 2: Confirm کردن Permissions <a class="header-anchor" href="#step-2-confirm-کردن-permissions" aria-label="Permalink to &quot;Step 2: Confirm کردن Permissions&quot;">​</a></h3><p>برای integration فعلی ImgBed با Yandex، این چهار permission زیر <code>Yandex.Disk REST API</code> را نگه دارید:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>اجازه می‌دهد ImgBed files را در app folder ذخیره کند</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>خواندن files و download links</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>upload files، ساخت folders و delete files</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>خواندن disk quota و used space</td></tr></tbody></table><p>اگر این permissions را زیر <code>Yandex ID API</code> هم دیدید، اختیاری هستند:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>Optional</td></tr><tr><td><code>Access to email address</code></td><td>Optional</td></tr></tbody></table><p>قابلیت‌های اصلی upload، download، deletion و quota عمدتاً به چهار permission مربوط به <code>Yandex.Disk REST API</code> بالا وابسته‌اند.</p><p><img src="'+t+'" alt="Configure Yandex Disk permissions" loading="lazy"></p><h3 id="step-3-copy-کردن-app-credentials" tabindex="-1">Step 3: Copy کردن App Credentials <a class="header-anchor" href="#step-3-copy-کردن-app-credentials" aria-label="Permalink to &quot;Step 3: Copy کردن App Credentials&quot;">​</a></h3><p>پس از ساخت app، copy کنید:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Record Client ID and Secret" loading="lazy"></p><h3 id="step-4-پر-کردن-yandex-channel" tabindex="-1">Step 4: پر کردن Yandex Channel <a class="header-anchor" href="#step-4-پر-کردن-yandex-channel" aria-label="Permalink to &quot;Step 4: پر کردن Yandex Channel&quot;">​</a></h3><p>در Upload Settings، <code>Yandex</code> را انتخاب کنید و پر کنید:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>What To Enter</th></tr></thead><tbody><tr><td>Channel name</td><td>نام قابل‌تشخیص، مثل <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td><code>Client ID</code> مربوط به Yandex app</td></tr><tr><td>Client Secret</td><td><code>Client Secret</code> مربوط به Yandex app</td></tr><tr><td>Refresh Token</td><td>فعلاً خالی بگذارید</td></tr><tr><td>Root directory</td><td>اختیاری. پیش‌فرض <code>imgbed</code>.</td></tr></tbody></table><p><img src="'+d+'" alt="Edit channel config" loading="lazy"></p><h3 id="step-5-گرفتن-refresh-token" tabindex="-1">Step 5: گرفتن Refresh Token <a class="header-anchor" href="#step-5-گرفتن-refresh-token" aria-label="Permalink to &quot;Step 5: گرفتن Refresh Token&quot;">​</a></h3><ol><li>در ImgBed، <code>Get Token</code> را بزنید.</li><li>وارد Yandex account موردنظر شوید.</li><li>authorization prompt را approve کنید.</li><li>callback page یک <code>Refresh Token</code> نشان می‌دهد.</li><li>آن را copy کنید.</li><li>به ImgBed برگردید و در <code>Refresh Token</code> paste کنید.</li></ol><p><img src="'+n+`" alt="Copy refresh token after authorization" loading="lazy"></p><h3 id="step-6-save-کردن-channel" tabindex="-1">Step 6: Save کردن Channel <a class="header-anchor" href="#step-6-save-کردن-channel" aria-label="Permalink to &quot;Step 6: Save کردن Channel&quot;">​</a></h3><p>پس از پر کردن همه fields، channel را save کنید.</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console را باز کنید</span></span>
<span class="line"><span>-&gt; app بسازید</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/yandex/callback را اضافه کنید</span></span>
<span class="line"><span>-&gt; Yandex Disk permissions را confirm کنید</span></span>
<span class="line"><span>-&gt; Client ID و Client Secret را copy کنید</span></span>
<span class="line"><span>-&gt; Client ID / Client Secret را در ImgBed وارد کنید</span></span>
<span class="line"><span>-&gt; Get Token را بزنید</span></span>
<span class="line"><span>-&gt; Refresh Token را از callback page copy کنید</span></span>
<span class="line"><span>-&gt; در ImgBed paste و save کنید</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const k=o(r,[["render",p]]);export{g as __pageData,k as default};
